const llmOutput = $input.first().json.text;

let parsed;
try {
  // Try to parse directly
  parsed = JSON.parse(llmOutput);
} catch (e) {
  // Try to extract JSON from markdown code fences
  const match = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    parsed = JSON.parse(match[1].trim());
  } else {
    throw new Error('Could not parse LLM output as JSON: ' + llmOutput.substring(0, 200));
  }
}

// Get the original request body for database path
const webhookData = $('Webhook').first().json.body;

return {
  json: {
    sql: parsed.sql,
    explanation: parsed.explanation,
    database: webhookData.database || '/data/source.duckdb'
  }
};

const queryResult = $input.first().json;
const parseData = $('Parse SQL').first().json;

// Handle error from duckdb-service
if (queryResult.status === 'error' || queryResult.detail) {
  return {
    json: {
      status: 'error',
      output: {
        error: queryResult.detail || 'Query execution failed',
        sql: parseData.sql,
        explanation: parseData.explanation
      }
    }
  };
}

return {
  json: {
    status: 'success',
    output: {
      columns: queryResult.columns || [],
      data: queryResult.rows || [],
      row_count: queryResult.row_count || 0,
      sql: parseData.sql,
      explanation: parseData.explanation
    }
  }
};
